(
	@id int,
	@masp nvarchar(200),
	@mact nvarchar(50),
	@stt nvarchar(50),
	@chitiet nvarchar(MAX),
	@nguyenlieu nvarchar(50), 
	@id_nguyenlieu nvarchar(50) = NULL, 
	@dayy_tc float, 
	@rong_tc float, 
	@dai_tc float, 
	@soluong_tc int, 
	@m3_tc float, 
	@m2_tc float, 
	@dayy_sc float, 
	@rong_sc float, 
	@dai_sc float,
	@soluong_sc int,
	@m3_sc float, 
	@ghichu nvarchar(MAX), 
	@ngaytao datetime, 
	@nguoitao nvarchar(50), 
	@ngaysua datetime, 
	@nguoisua nvarchar(50),
	@hoanthanh bit,
	@veneer_matchinh nvarchar(200) = null,
	@veneer_matphu nvarchar(200)= null,
	@mong1 float= null,
	@mong2 float = null,
	@veneer_dan_canh nvarchar(200)= null,
	@uv_canhngan int= null,
	@uv_canhdai int = null,
	@uv_matchinh bit = null,
	@uv_matphu bit = null,
	@veneer_canhngan int= null,
	@veneer_canhdai int = null,
	@banve nvarchar(max) = null,
	@fsc_100 bit = null,
	@fsc_mix bit = null,
	@fsc_cw bit = null,
	@uv_matchinh1 int = null,
	@uv_matphu1 int = null,
	@uv_canhngan1 int = null,
	@uv_canhdai1 int = null,
	@fsc_recycled bit = null, 
	@non_fsc bit = null,
	@fsc_id int = null,
	@uv_code nvarchar(50) = NULL,
	@pcode nvarchar(50) = NULL,
	@phoi_tructiep bit = 0
)
AS
BEGIN
	IF @id_nguyenlieu IS NOT NULL
	BEGIN
		SELECT @nguyenlieu = nguyenlieu
		FROM tr_nguyenlieu_gva 
		WHERE id = @id_nguyenlieu
	END

	UPDATE mes_dinhmuc_govan
	SET masp = @masp,
		mact = @mact,
		stt = @stt,
		chitiet = @chitiet,
		id_nguyenlieu = @id_nguyenlieu,
		nguyenlieu = @nguyenlieu, 
		dayy_tc = @dayy_tc, 
		rong_tc = @rong_tc, 
		dai_tc = @dai_tc, 
		soluong_tc = @soluong_tc, 
		m3_tc = @m3_tc, 
		m2_tc = @m2_tc, 
		dayy_sc = @dayy_sc, 
		rong_sc = @rong_sc, 
		dai_sc = @dai_sc,
		soluong_sc = @soluong_sc,
		m3_sc = @m3_sc, 
		ghichu = @ghichu, 
		ngaysua = @ngaysua, 
		nguoisua = @nguoisua,
		hoanthanh = @hoanthanh,
		veneer_matchinh = @veneer_matchinh,
		veneer_matphu = @veneer_matphu,
		mong1 = @mong1,
		mong2 = @mong2,
		veneer_dan_canh = @veneer_dan_canh,
		uv_canhngan = @uv_canhngan,
		uv_canhdai = @uv_canhdai,
		uv_matchinh = @uv_matchinh,
		uv_matphu = @uv_matphu,
		veneer_canhdai = @veneer_canhdai,
		veneer_canhngan = @veneer_canhngan,
		banve = @banve,
		fsc_100 = @fsc_100,
		fsc_mix = @fsc_mix,
		fsc_cw = @fsc_cw,
		fsc_recycled = @fsc_recycled,
		non_fsc = @non_fsc,
		uv_matchinh1 = @uv_matchinh1,
		uv_matphu1 = @uv_matphu1,
		uv_canhngan1 = @uv_canhngan1,
		uv_canhdai1 = @uv_canhdai1,
		fsc_id = @fsc_id,
		uv_code = @uv_code,
		pcode = @pcode,
		phoi_tructiep = @phoi_tructiep
	WHERE id = @id

	IF EXISTS (SELECT 1 FROM mes_quytrinh_sanpham WHERE masp = @masp AND mact = @mact)
	BEGIN
		UPDATE mes_quytrinh_sanpham
		SET stt = @stt,
			tenct = @chitiet,
			nguyenlieu = @nguyenlieu,
			dayy_tc = @dayy_tc,
			rong_tc = @rong_tc,
			dai_tc = @dai_tc
		WHERE masp = @masp AND mact = @mact
	END
	--ELSE
	--BEGIN
	--	INSERT INTO mes_quytrinh_sanpham 
	--	(
	--		id, masp, 
	--		mact, tenct, 
	--		nguyenlieu, 
	--		dayy_tc, rong_tc, dai_tc, active
	--	)
	--	VALUES
	--	(
	--		NEWID(), @masp,
	--		@mact, @chitiet,
	--		@nguyenlieu,
	--		@dayy_tc, @rong_tc, @dai_tc, 1
	--	)
	--END
END

